// WF-005 — Alert Threshold Evaluation (§387/§569), PR-1 slice.
// Aggregates the upstream branches by their EXPLICIT _source tag (never by
// payload shape), so it is deterministic and resilient to schema changes.
// Thresholds are config-driven ($vars.CRIE_ALERT_THRESHOLDS); no hardcoded
// values (Principle 7).
const cfg = $vars.CRIE_ALERT_THRESHOLDS ? JSON.parse($vars.CRIE_ALERT_THRESHOLDS) : {};
const corr = $('Initialize').first().json.correlation_id;

// Group every incoming item by its source identifier.
const bySource = {};
for (const it of $input.all()) {
  const j = it.json || {};
  if (!j._source) continue;
  (bySource[j._source] = bySource[j._source] || []).push(j);
}

const alerts = [];
const raise = (alert_type, severity, source, message, context) =>
  alerts.push({ alert_type, severity, source, message,
    context: JSON.stringify(context || {}), correlation_id: corr });

// --- Cost (daily) threshold ---
const cost = (bySource['cost_report'] || [])[0];
if (cost && cfg.daily_cost_max !== undefined && cost.daily_cost != null
    && Number(cost.daily_cost) > Number(cfg.daily_cost_max)) {
  raise('HighCost', 'Warning', 'cost', 'Daily cost above threshold',
    { observed: cost.daily_cost, threshold: cfg.daily_cost_max });
}

// --- Component health: any non-Healthy component ---
for (const h of (bySource['repository_health'] || [])) {
  if (h.state && h.state !== 'Healthy') {
    raise('ProviderFailure',
      (h.state === 'Offline' || h.state === 'Critical') ? 'Critical' : 'Warning',
      h.component || 'unknown', 'Component health degraded',
      { component: h.component, state: h.state });
  }
}

// --- Orphan sweep RUN health (not per-document; the sweep self-alerts those) ---
// A completed sweep emits a summary carrying remediated_count. Its absence means
// the sweep branch errored/produced nothing this run -> surface that.
const sweepItems = bySource['orphan_sweep'] || [];
const sweepCompleted = sweepItems.some(s => typeof s.remediated_count !== 'undefined');
if (!sweepCompleted) {
  raise('WorkflowFailure', 'Warning', 'orphan-sweep',
    'Orphan sweep did not complete on this admin run',
    { note: 'no sweep summary received (branch errored or empty)' });
}

// repository_statistics is aggregated in bySource['repository_statistics'] and
// available for future rules; no threshold is defined for it in the PR-1 slice.

return alerts.map(a => ({ json: a }));
